1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office - quote", () => {
6	  // Empty / processing fee
7	  it("empty item list yields premium 5 G (only processing fee)", () => {
8	    expect(quote({ items: [], customer: { yearsInsured: 0, previousQuotes: 0 } })).toBe(5);
9	  });
10	
11	  // Single main item base premiums
12	  it("single plain sword (newcomer, first insurance) yields 115 G (100 base + 10 first + 5 fee)", () => {
13	    expect(
14	      quote({
15	        items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
16	        customer: { yearsInsured: 0, previousQuotes: 0 },
17	      })
18	    ).toBe(115);
19	  });
20	  it("single plain amulet (newcomer, first insurance) yields 71 G (60 base + 6 first + 5 fee)", () => {
21	    expect(
22	      quote({
23	        items: [{ type: "amulet", material: "steel", enchantment: 0, cursed: false }],
24	        customer: { yearsInsured: 0, previousQuotes: 0 },
25	      })
26	    ).toBe(71);
27	  });
28	  it("single plain staff (newcomer, first insurance) yields 93 G (80 base + 8 first + 5 fee)", () => {
29	    expect(
30	      quote({
31	        items: [{ type: "staff", material: "steel", enchantment: 0, cursed: false }],
32	        customer: { yearsInsured: 0, previousQuotes: 0 },
33	      })
34	    ).toBe(93);
35	  });
36	  it("single plain potion (newcomer, first insurance) yields 49 G (40 base + 4 first + 5 fee)", () => {
37	    expect(
38	      quote({
39	        items: [{ type: "potion", material: "steel", enchantment: 0, cursed: false }],
40	        customer: { yearsInsured: 0, previousQuotes: 0 },
41	      })
42	    ).toBe(49);
43	  });
44	
45	  // Components - building block rule
46	  it.todo("2 runes yields base premium 50 G (25 each, no block)");
47	  it.todo("3 runes yields base premium 60 G (block applies)");
48	  it.todo("4 runes yields base premium 100 G (no block - requires exactly 3)");
49	  it.todo("7 runes yields base premium 175 G (one block of 3 + 4 singles)");
50	
51	  // Alike components
52	  it.todo("2 runes + 1 moonstone yields base premium 75 G (different types, no block)");
53	  it.todo("3 runes + 3 moonstones yields base premium 120 G (two separate blocks)");
54	
55	  // Item-specific modifiers: cursed
56	  it.todo("cursed sword (newcomer) yields 165 G (100 base + 50 curse + 10 first + 5 fee)");
57	
58	  // Item-specific modifiers: high enchantment
59	  it.todo("sword with enchantment exactly 5 (newcomer) triggers high-enchantment surcharge");
60	  it.todo("sword with enchantment 4 (newcomer) does not trigger high-enchantment surcharge");
61	
62	  // Modifier scope on multi-item policies
63	  it.todo("policy with cursed sword and plain amulet: curse surcharge applies only to sword's base premium");
64	
65	  // Policy-wide modifiers: loyalty
66	  it.todo("customer with exactly 2 years receives 20% loyalty discount");
67	
68	  // Policy-wide modifiers: follow-up contract
69	  it.todo("customer's second quote receives 15% follow-up discount");
70	
71	  // Rounding
72	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G (in MHPCO's favor)");
73	
74	  // Integration examples
75	  it.todo("newcomer with cursed sword (steel, enchantment 3) yields 165 G");
76	  it.todo("long-standing customer (3 years) second quote, cursed sword enchantment 7 yields 160 G");
77	});
78	
79	describe("MHPCO Claim Office - claim", () => {
80	  // Standard reimbursement
81	  it.todo("regular sword (steel, enchantment 3), damage 500 G yields payout 400 G");
82	  it.todo("rune damage 200 G yields payout 100 G");
83	
84	  // Deductible per damage event
85	  it.todo("dragon attack damaging sword (500 G) and amulet (300 G) yields payout 600 G");
86	
87	  // High enchantment threshold
88	  it.todo("steel sword enchantment 9, damage 1000 G yields payout 400 G (50% then deductible)");
89	
90	  // Dragon material
91	  it.todo("dragon-material sword enchantment 5, damage 800 G yields payout 700 G (full minus deductible)");
92	
93	  // Both clauses: enchantment >= 8 wins (50% rule)
94	  it.todo("dragon-material sword enchantment 9, damage 1000 G yields payout 400 G");
95	  it.todo("dragon-material sword enchantment exactly 8, damage 1000 G yields payout 400 G");
96	
97	  // Cap based on unmodified insurance sum
98	  it.todo("cursed sword has cap 2000 G (based on unmodified insurance value)");
99	  it.todo("sword + 3 runes policy has insurance sum 1750 G (block discount doesn't affect insurance sum)");
100	
101	  // Cap exhaustion across multiple claims
102	  it.todo("sword (cap 2000): first claim 1500 G yields payout 1400 G, remaining cap 600 G");
103	  it.todo("sword (cap 2000) after first 1400 G payout: second claim 1500 G yields payout 600 G, remaining cap 0");
104	
105	  // Multiple items of same type
106	  it.todo("policy with two swords: dragon attack on both treats each as separate damage with own deductible");
107	
108	  // Rounding for payout
109	  it.todo("payout calculation yielding 350.5 G rounds down to 350 G (in MHPCO's favor)");
110	});
111	
112	describe("MHPCO Claim Office - CLI", () => {
113	  it.todo("reads scenario JSON from stdin and writes results JSON to stdout");
114	  it.todo("quote step result contains premium (integer)");
115	  it.todo("claim step result contains payout and remainingCap (integers)");
116	  it.todo("claim references policy by zero-based step index");
117	
118	  // Error cases
119	  it.todo("unknown item type in quote exits non-zero with stderr message and no results on stdout");
120	  it.todo("claim referencing item not in policy exits non-zero with stderr message");
121	  it.todo("claim with negative damage amount exits non-zero with stderr message");
122	  it.todo("claim with more damage entries of a type than policy covers exits non-zero");
123	});
