3	const PROCESSING_FEE = 5;
4	
5	const PLAIN_NEWCOMER_PREMIUM_BY_TYPE: Record<string, number> = {
6	  sword: 115,
7	  amulet: 71,
8	  staff: 93,
9	};
10	
11	export type Customer = {
12	  yearsInsured: number;
13	  previousQuotes: number;
14	};
15	
16	export type Item = {
17	  type: string;
18	};
19	
20	export type QuoteInput = {
21	  items: Item[];
22	  customer: Customer;
23	};
24	
25	export const quote = (input: QuoteInput): number => {
26	  const { items } = input;
27	  if (items.length === 0) return PROCESSING_FEE;
28	  return PLAIN_NEWCOMER_PREMIUM_BY_TYPE[items[0].type];
29	};
